import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import { LayoutDashboard, History, PlusCircle, ArrowUpRight, ShieldCheck } from 'lucide-react';

const DashboardPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchVaultData = async () => {
      try {
        const res = await api.get('/portfolio/history');
        setHistory(res.data);
      } catch (err) {
        console.error("VAULT_SYNC_ERROR", err);
      } finally {
        setLoading(false);
      }
    };
    fetchVaultData();
  }, []);

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-40 animate-pulse">
      <div className="w-16 h-1 bg-emerald-500/20 rounded-full overflow-hidden mb-4">
        <div className="h-full bg-emerald-500 w-1/2 animate-infinite" />
      </div>
      <p className="text-[10px] text-emerald-500 uppercase tracking-[0.4em]">decrypting_vault...</p>
    </div>
  );

  return (
    <div className="max-w-5xl mx-auto reveal-data">
      {/* Dashboard Header */}
      <div className="flex justify-between items-end mb-12 border-b border-white/5 pb-8">
        <div>
          <h1 className="flex items-center gap-3 text-3xl font-bold tracking-tighter text-white uppercase">
            <LayoutDashboard className="text-emerald-500" size={28} />
            Terminal_<span className="text-emerald-500">Dashboard</span>
          </h1>
          <p className="text-[10px] text-white/30 uppercase tracking-[0.3em] mt-3">
            Secure Node Active // Location: Pune, IN
          </p>
        </div>
        <div className="hidden md:block text-right">
          <div className="flex items-center gap-2 text-emerald-500/50 text-[10px] font-bold uppercase mb-1">
            <ShieldCheck size={12} /> System_Health
          </div>
          <p className="text-xl font-bold text-white tracking-widest">OPTIMAL</p>
        </div>
      </div>

      {/* Strategy Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {history.map((item) => (
          <div 
            key={item.id} 
            onClick={() => navigate(`/portfolio/${item.id}`)}
            className="terminal-card group cursor-pointer relative overflow-hidden"
          >
            <div className="flex justify-between items-start mb-6">
              <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-500">
                <History size={18} />
              </div>
              <ArrowUpRight size={18} className="text-white/10 group-hover:text-emerald-500 transition-colors" />
            </div>
            
            <h3 className="text-lg font-bold text-white group-hover:text-emerald-400 transition-colors line-clamp-1">
              {item.goal || "Unnamed Strategy"}
            </h3>
            
            <div className="mt-6 flex items-center justify-between border-t border-white/5 pt-4">
              <span className="text-[9px] text-white/40 uppercase tracking-widest">
                Analyzed: {new Date(item.created_at).toLocaleDateString()}
              </span>
              <span className="text-[10px] text-emerald-500 font-bold underline opacity-0 group-hover:opacity-100 transition-opacity">
                VIEW_DETAILS
              </span>
            </div>
          </div>
        ))}

        {/* Action Card: Initialize New Strategy */}
        <button 
          onClick={() => navigate('/generate')}
          className="col-span-1 md:col-span-2 py-16 border-2 border-dashed border-white/5 rounded-2xl flex flex-col items-center justify-center hover:bg-emerald-500/5 hover:border-emerald-500/20 transition-all group"
        >
          <div className="p-4 bg-white/5 rounded-full mb-4 group-hover:scale-110 transition-transform">
            <PlusCircle className="text-white/20 group-hover:text-emerald-500" size={32} />
          </div>
          <p className="text-white/40 text-xs uppercase tracking-[0.2em]">Vault_Is_Empty: No_Strategies_Generated</p>
          <span className="text-emerald-500 text-[11px] font-bold mt-3 group-hover:tracking-widest transition-all">
            INITIALIZE_STRATEGY_ENGINE →
          </span>
        </button>
      </div>
    </div>
  );
};

export default DashboardPage;
